mapper.select:
SELECT recorder, COUNT(*) as count
FROM eco_chain_complete_record
WHERE recording_time BETWEEN #{startTime}
  AND #{endTime}
  AND recorder LIKE CONCAT('%'
    , #{name}
    , '%')
  AND social_credit_code = #{socialCreditCode}
GROUP BY recorder

SELECT b.detail_type_option as detailTypeOption, COUNT(*) as count
FROM eco_chain_complete_record a
    JOIN eco_chain_build_warehouse b
ON a.eco_chain_build_warehouse_id = b.id
WHERE a.recording_time BETWEEN #{startTime}
  AND #{endTime}
  AND b.detail_type_option LIKE CONCAT('%'
    , #{name}
    , '%')
  AND a.social_credit_code = #{socialCreditCode}
GROUP BY b.detail_type_option;

SELECT b.industry_group_option as industryGroupOption, COUNT(*) as count
FROM eco_chain_complete_record a
    JOIN eco_chain_build_warehouse b
ON a.eco_chain_build_warehouse_id = b.id
WHERE a.recording_time BETWEEN #{startTime}
  AND #{endTime}
  AND b.industry_group_option LIKE CONCAT('%'
    , #{name}
    , '%')
  AND a.social_credit_code = #{socialCreditCode}
GROUP BY b.industry_group_option;

SELECT b.industry_warehouse as industryWarehouse, COUNT(*) as count
FROM eco_chain_complete_record a
    JOIN eco_chain_build_warehouse b
ON a.eco_chain_build_warehouse_id = b.id
WHERE a.recording_time BETWEEN #{startTime}
  AND #{endTime}
  AND b.industry_warehouse LIKE CONCAT('%'
    , #{name}
    , '%')
  AND a.social_credit_code = #{socialCreditCode}
GROUP BY b.industry_warehouse;
